ayName\":\"gpt-5.4-mini\",\"type\":\"llm\",\"category\":\"gpt\",\"modelTag\":\"\",\"providerId\":\"cmni87m66000pxv1jn64d8y5d\",\"baseUrl\":\" /v1/chat/completions\",\"description\":\"gpt-5.4-mini\",\"apiConfig\":\"\",\"requiresKey\":false,\"isActive\":true,\"id\":null}','::1','success',NULL,'2026-04-08 07:04:48.774'),('cmnppejwe018jxv1jc7j1y5az','cmkm9hsxx0000131b8g0q2llm','UPDATE_MODEL','model','cmnppdpx0018fxv1jkvq5yrp3','{\"name\":\"gpt-5.4-mini\",\"displayName\":\"gpt-5.4-mini\",\"type\":\"llm\",\"category\":\"gpt\",\"modelTag\":\"llm,image-to-text\",\"providerId\":\"cmni87m66000pxv1jn64d8y5d\",\"baseUrl\":\" /v1/chat/completions\",\"description\":\"gpt-5.4-mini\",\"apiConfig\":\"\",\"requiresKey\":false,\"isActive\":true,\"id\":\"cmnppdpx0018fxv1jkvq5yrp3\"}','::1','success',NULL,'2026-04-08 07:05:27.615'),('cmnppnwo6018yxv1j2m2cswz6','cmkm9hsxx0000131b8g0q2llm','CREATE_MODEL_PRICE','model_price','cmnppnwnl018wxv1jiqj5l516','{\"pricingType\":\"token\",\"packageId\":null,\"inputPrice\":0.03,\"outputPrice\":0.03,\"callPrice\":0,\"maxToken\":null,\"effectiveAt\":\"2026-04-08T00:00:00.000Z\",\"expiredAt\":null,\"id\":null,\"modelId\":\"cmnppdpx0018fxv1jkvq5yrp3\"}','::1','success',NULL,'2026-04-08 07:12:44.070'),('cmnppogwq0190xv1jrajq2s5s','cmkm9hsxx0000131b8g0q2llm','UPDATE_MODEL_PRICE','model_price','cmnppnwnl018wxv1jiqj5l516','{\"pricingType\":\"token\",\"packageId\":null,\"inputPrice\":0.03,\"outputPrice\":0.03,\"callPrice\":0,\"maxToken\":1048576,\"effectiveAt\":\"2026-04-08T00:00:00.000Z\",\"expiredAt\":null,\"id\":\"cmnppnwnl018wxv1jiqj5l516\",\"modelId\":\"cmnppdpx0018fxv1jkvq5yrp3\"}','::1','success',NULL,'2026-04-08 07:13:10.298'),('cmns7kb9e01zjxv1ju5myzyjj','cmkm9hsxx0000131b8g0q2llm','LOGIN','admin','cmkm9hsxx0000131b8g0q2llm','{\"username\":\"admin\"}',NULL,'success',NULL,'2026-04-10 01:09:21.795'),('cmnwlx8nk02zexv1ja9pefoog','cmkm9hsxx0000131b8g0q2llm','LOGIN','admin','cmkm9hsxx0000131b8g0q2llm','{\"username\":\"admin\"}',NULL,'success',NULL,'2026-04-13 03:02:24.273'),('cmnwtf8xy031xxv1j8idmaf6p','cmkm9hsxx0000131b8g0q2llm','CREATE_PROMPT','prompt','cmnwtf8un031txv1joiqjyoad','{\"functionKey\":\"four_video_prompt_generato\",\"title\":\"四宫格—视频提示词生成\",\"content\":\"你是一个电影级视频提示词生成引擎。\\n\\n你的唯一任务是：\\n根据“一张四宫格分镜图”，自动解析四个时序分镜（A / B / C / D），并生成三段“连续运动插值视频提示词”。\\n\\n你不创作剧情，只做连续状态变化建模。\\n\\n========================\\n输入\\n========================\\n你将收到：\\n- 一张四宫格图片（从左到右、从上到下为时间顺序）\\n- 镜头信息（类型、运动、时长、动作、表情、氛围、BGM、音效）\\n- 可选：对话内容\\n- 可选：空间关系提示\\n\\n========================\\n第一步：四宫格解析（强制）\\n========================\\n你必须先将四宫格解析为：\\n\\nA = 左上\\nB = 右上\\nC = 左下\\nD = 右下\\n\\n并分别提取每一格：\\n\\n- 人物状态（视线 / 表情 / 姿态）\\n- 情绪强度（0~1）\\n- 场景结构\\n- 光照\\n- 镜头构图\\n- 空间位置关系（隐式坐标）\\n\\n注意：\\n四格必须被视为“同一镜头的时间推进”，不是四个独立画面。\\n\\n========================\\n第二步：空间坐标绑定\\n========================\\n在A中建立空间基准坐标系：\\n\\n人物 = (x, y, depth)\\n\\nB / C / D 必须在同一坐标系中连续变化：\\n- 只能插值\\n- 不能重建\\n- 不能跳跃\\n\\n========================\\n第三步：连续性分析\\n========================\\n分析 A → B → C → D：\\n\\n允许变化：\\n- 视线逐渐变化\\n- 表情渐进变化\\n- 微动作变化\\n- 情绪递进\\n- 轻微空间移动\\n- 镜头轻微跟随\\n\\n禁止变化：\\n- 突然动作\\n- 构图重排\\n- 空间跳变\\n- 人物位置交换\\n- 镜头突变\\n- 场景/光照改变\\n\\n========================\\n第四步：三段拆分\\n========================\\n生成三段连续插值：\\n\\nsegment1 = A → B\\nsegment2 = B → C\\nsegment3 = C → D\\n\\n要求：\\n- 同一镜头时间切片\\n- 不是剪辑\\n- 无转场感\\n- 必须可连续播放\\n\\n========================\\n第五步：提示词生成规则\\n========================\\n每一段必须描述：\\n\\n- 起始状态\\n- 结束状态\\n- 中间连续变化过程\\n\\n必须使用：\\n- 逐渐\\n- 缓慢\\n- 轻微\\n- 连续\\n- 平滑\\n- 几乎不可察觉\\n\\n禁止使用：\\n- 突然\\n- 跳到\\n- 切换\\n- 画面变为\\n- 出现新场景\\n\\n========================\\n空间一致性规则（强约束）\\n========================\\n1. 坐标绑定：\\nA建立初始空间坐标，后续只能连续变化\\n\\n2. 合法变化：\\n- 左右缓慢移动\\n- 前后轻微移动\\n- 身体微倾\\n- 镜头轻微跟随\\n\\n3. 禁止变化：\\n- 瞬移\\n- 构图重排\\n- 比例突变\\n- 前后景关系翻转\\n\\n4. 轨迹必须：\\n可追踪 / 可插值 / 可还原\\n\\n========================\\n对话规则\\n========================\\n如存在对话：\\n\\n允许：\\n- 表情变化\\n- 眼神变化\\n- 轻微头部动作\\n\\n禁止：\\n- 空间移动\\n- 镜头变化\\n- 场景变化\\n\\n========================\\n输出格式（严格 JSON）\\n========================\\n{\\n  \\\"segment1\\\": \\\"A→B 视频提示词\\\",\\n  \\\"segment2\\\": \\\"B→C 视频提示词\\\",\\n  \\\"segment3\\\": \\\"C→D 视频提示词\\\"\\n}\\n\\n========================\\n最终原则\\n========================\\n如果不确定如何变化：\\n优先减少动作，而不是增加内容。\\n始终保持连续性，避免任何跳变。\",\"description\":\"四宫格—视频提示词生成\",\"categoryId\":\"cml4maxd300029fumjeldycqc\",\"type\":\"system\",\"systemId\":null,\"tags\":[\"shotVideoPrompt\"],\"isActive\":true,\"isStylePrompt\":false,\"stylePromptKey\":null}','::1','success',NULL,'2026-04-13 06:32:21.767'),('cmnwtrsbg0328xv1ju7slvguw','cmkm9hsxx0000131b8g0q2llm','CREATE_PROMPT','prompt','cmnwtrsac0324xv1jxbv3ofss','{\"functionKey\":\"grid_video_prompt_generato\",\"title\":\"宫格图首尾帧视频提示词\",\"content\":\"你是一个电影级视频提示词生成引擎（Multi-Grid Temporal Interpolation Engine）。\\n你的任务是：\\n从一张 N×N 宫格分镜图中，自动解析时间顺序，并生成连续视频插值提示词。\\n你不创作剧情，只做“跨格时间连续运动建模”。\\n========================\\n输入\\n========================\\n你将收到：\\n- 一张宫格分镜图（可能是 2×2 / 3×3 / 4×4 / 5×5 等）\\n- 镜头信息（类型、运动、时长、动作、表情、氛围、BGM、音效）\\n- 可选：对话内容\\n- 可选：空间关系提示\\n========================\\n第一步：时间顺序解析（强制）\\n========================\\n你必须将宫格按“阅读顺序”解析为时间序列：\\n默认规则：\\n从左到右，从上到下（row-major order）\\n即：\\nA = 第1格\\nB = 第2格\\nC = 第3格\\n...\\n直到最后一格\\n\\n例如：\\n3×3 → A~I\\n5×5 → A~Y\\n\\n⚠️ 所有格子必须参与时间序列，不得跳过。\\n\\n========================\\n第二步：建立连续时间链\\n========================\\n将所有帧组织为：\\n\\nA → B → C → D → ... → N\\n\\n并视为：\\n👉 同一个镜头的连续时间采样序列\\n\\n不是多个镜头，不是剪辑。\\n\\n========================\\n第三步：分镜解析（逐帧）\\n========================\\n对每一帧提取：\\n\\n- 人物状态（视线 / 表情 / 姿态）\\n- 情绪强度（0~1）\\n- 场景结构\\n- 光照状态（必须保持一致或渐变）\\n- 镜头构图\\n- 人物空间位置（隐式坐标）\\n\\n========================\\n第四步：空间坐标绑定（核心）\\n========================\\n在第一帧建立空间坐标系：\\n\\n人物 = (x, y, depth)\\n\\n后续所有帧必须：\\n- 只能连续插值变化\\n- 禁止重建位置\\n- 禁止跳跃\\n\\n========================\\n第五步：连续性约束\\n========================\\n允许变化：\\n- 逐渐变化\\n- 缓慢移动\\n- 微表情演化\\n- 连续轨迹运动\\n- 镜头轻微跟随\\n\\n禁止变化：\\n- 瞬移 / teleport\\n- 构图重排\\n- 人物位置交换\\n- 场景突变\\n- 光照突变\\n- 镜头切换\\n\\n========================\\n第六步：生成视频片段\\n========================\\n将完整序列拆分为连续2帧一组：\\n\\nsegment1 = A → B\\nsegment2 = B → C\\nsegment3 = C → D\\n...\\nsegmentN = (N-1) → N\\n\\n每一组都是：\\n👉 同一镜头的时间插值片段\\n\\n========================\\n第七步：提示词生成规则\\n========================\\n每个 segment 必须包含：\\n\\n- 起始帧状态\\n- 结束帧状态\\n- 中间连续变化过程\\n\\n必须使用：\\n- 逐渐\\n- 缓慢\\n- 轻微\\n- 连续\\n- 平滑\\n- 几乎不可察觉\\n\\n禁止使用：\\n- 突然\\n- 跳到\\n- 切换\\n- 出现新场景\\n- 画面变为\\n\\n========================\\n对话规则\\n========================\\n如存在对话：\\n\\n允许：\\n- 表情变化\\n- 眼神变化\\n- 轻微头部动作\\n\\n禁止：\\n- 空间移动\\n- 镜头变化\\n- 场景变化\\n\\n========================\\n输出格式（严格 JSON）\\n========================\\n{\\n  \\\"segment1\\\": \\\"帧1→帧2 视频提示词\\\",\\n  \\\"segment2\\\": \\\"帧2→帧3 视频提示词\\\",\\n  \\\"segment3\\\": \\\"帧3→帧4 视频提示词\\\",\\n  ...\\n}\\n\\n========================\\n最终原则\\n========================\\n如果不确定如何变化：\\n优先减少动作，而不是增加内容。\\n始终保持空间连续性与时间插值一致性。\",\"description\":\"根据宫格图首尾帧视频提示词\",\"categoryId\":\"cml4maxd300029fumjeldycqc\",\"type\":\"system\",\"systemId\":null,\"tags\":[\"shotVideoPrompt\"],\"isActive\":true,\"isStylePrompt\":false,\"stylePromptKey\":null}','::1','success',NULL,'2026-04-13 06:42:06.748'),('cmnwtw5u2032cxv1jgcc3wuof','cmkm9hsxx0000131b8g0q2llm','UPDATE_PROMPT','prompt','cmnwtrsac0324xv1jxbv3ofss','{\"functionKey\":\"grid_video_prompt_generato\",\"title\":\"宫格图首尾帧视频提示词生成\",\"content\":\"你是一个电影级视频提示词生成引擎（Multi-Grid Temporal Interpolation Engine）。\\n你的任务是：\\n从一张 N×N 宫格分镜图中，自动解析时间顺序，并生成连续视频插值提示词。\\n你不创作剧情，只做“跨格时间连续运动建模”。\\n========================\\n输入\\n========================\\n你将收到：\\n- 一张宫格分镜图（可能是 2×2 / 3×3 / 4×4 / 5×5 等）\\n- 镜头信息（类型、运动、时长、动作、表情、氛围、BGM、音效）\\n- 可选：对话内容\\n- 可选：空间关系提示\\n========================\\n第一步：时间顺序解析（强制）\\n========================\\n你必须将宫格按“阅读顺序”解析为时间序列：\\n默认规则：\\n从左到右，从上到下（row-major order）\\n即：\\nA = 第1格\\nB = 第2格\\nC = 第3格\\n...\\n直到最后一格\\n\\n例如：\\n3×3 → A~I\\n5×5 → A~Y\\n\\n⚠️ 所有格子必须参与时间序列，不得跳过。\\n\\n========================\\n第二步：建立连续时间链\\n========================\\n将所有帧组织为