--
-- Table structure for table `prompts`
--

DROP TABLE IF EXISTS `prompts`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `prompts` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `title` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `content` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `categoryId` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `tags` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `type` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `userId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `version` int NOT NULL DEFAULT '1',
  `isActive` tinyint(1) NOT NULL DEFAULT '1',
  `createdAt` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updatedAt` datetime(3) NOT NULL,
  `systemId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `functionKey` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `isStylePrompt` tinyint(1) NOT NULL DEFAULT '0',
  `stylePromptKey` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `prompts_functionKey_key` (`functionKey`),
  KEY `prompts_categoryId_idx` (`categoryId`),
  KEY `prompts_type_idx` (`type`),
  KEY `prompts_userId_idx` (`userId`),
  KEY `prompts_isActive_idx` (`isActive`),
  KEY `prompts_title_idx` (`title`),
  KEY `prompts_systemId_idx` (`systemId`),
  KEY `prompts_functionKey_idx` (`functionKey`),
  CONSTRAINT `prompts_categoryId_fkey` FOREIGN KEY (`categoryId`) REFERENCES `prompt_categories` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `prompts_systemId_fkey` FOREIGN KEY (`systemId`) REFERENCES `prompts` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

